#include <bits/stdc++.h>
#define N 30010
using namespace std;
vector <int> e[2 * N];
int tot;
int dep[N], fa[N], siz[N], son[N], top[N];
int seg[N], rev[N], sum[N << 2], maxn[N << 2];
int n, m;
int num[N];
string op;
void dfs1 (int x) {
	siz[x] = 1;
	for (auto y : e[x]) {
		if (fa[x] == y) {
			continue;
		}
		fa[y] = x;
		dep[y] = dep[x] + 1;
		dfs1 (y);if (siz[son[x]] < siz[y]) {
			son[x] = y;
		}
		siz[x] += siz[y]; 
	}
	return ;
}
void dfs2 (int x) {
	if (!son[x]) {
		return ;
	}
	seg[son[x]] = ++seg[0];
	rev[seg[0]] = son[x];
	top[son[x]] = top[x];
	dfs2 (son[x]);
	for (auto y : e[x]) {
		if (y == fa[x] || y == son[x]) {
			continue;
		}
		seg[y] = ++seg[0];
		rev[seg[0]] = y;
		top[y] = y;
		dfs2 (y);
	}
	return ;
}
void build (int p, int l, int r) {
	if (l==r) {
		sum[p] = maxn[p] = num[rev[l]];
		return;
	}
	int mid = l + r >> 1;
	build (p << 1, l, mid);
	build (p << 1 | 1, mid + 1, r);
	sum[p] = sum[p << 1] + sum[p << 1 | 1];
	maxn[p] = max(maxn[p << 1], maxn[p << 1 | 1]);
	return ;
}
void modify (int p, int l, int r, int x, int val) {
	if (l == r) {
		sum[p] = maxn[p] = val;
		return ;
	}
	int mid = l + r >> 1;
	if (x <= mid) {
		modify (p << 1, l, mid, x, val);
	} else {
		modify (p << 1 | 1, mid + 1, r, x, val);
	}
	sum[p] = sum[p << 1] + sum[p << 1 | 1];
	maxn[p] = max (maxn[p << 1],maxn[p << 1 | 1]);
	return ;
}
int ask_sum(int p, int l, int r, int x, int y) {
	if (x <= l && r <= y) {
		return sum[p];
	}
	int mid = l + r >> 1, ans = 0;
	if (x <= mid) {
		ans = ask_sum (p << 1, l, mid, x, y);
	}
	if (y > mid) {
		ans += ask_sum (p << 1 | 1, mid + 1, r, x, y);
	}
	return ans;
}
int ask_max (int p, int l, int r, int x, int y) {
	if (x <= l && r <= y) {
		return maxn[p];
	}
	int mid = l + r >> 1;
	int ans = -30000;
	if (x <= mid) {
		ans = ask_max (p << 1, l, mid, x, y); 
	}
	if (y > mid) {
		ans = max (ans, ask_max (p << 1 | 1, mid + 1, r, x, y));
	}
	return ans;
}
int query_max (int x, int y) {
	int fx = top[x], fy = top[y];
	int ans = -30000;
	while (fx != fy) {
		if (dep[fx] < dep[fy]) {
			swap (x, y);
			swap (fx, fy);
		}
		ans = max (ans, ask_max (1, 1, n, seg[fx],seg[x]));
		x = fa[fx];
		fx = top[x];
	}
	if (dep[x] > dep[y]) {
		swap (x, y);
	}
	ans = max (ans, ask_max (1, 1, n, seg[x], seg[y]));
	return ans;
}
int query_sum (int x, int y) {
	int fx = top[x], fy = top[y], ans = 0;
	while (fx != fy) {
		if (dep[fx] < dep[fy]) {
			swap (x, y);
			swap (fx, fy);
		}
		ans += ask_sum (1, 1, n, seg[fx], seg[x]);
		x = fa[fx];
		fx = top[x];
	}
	if (dep[x] > dep[y]) {
		swap (x, y);
	}
	ans += ask_sum (1, 1, n, seg[x], seg[y]);
	return ans;
}
signed main() {
	cin >> n;
	int x, y;
	for (int i = 1; i < n; i++) {
		cin >> x >> y;
		e[x].push_back (y);
		e[y].push_back (x);
	}
	for (int i = 1; i <= n; i++) {
		cin >> num[i];
	}
	dep[1] = rev[1] = seg[0] = seg[1] = top[1] = 1;
	dfs1 (1);
	dfs2 (1);
	build (1, 1, n);
	cin >> m;
	while (m--) {
		cin >> op >> x >> y;
		if (op == "CHANGE") {
			modify (1, 1, n, seg[x], y);
		} else {
			if (op == "QMAX") {
				cout << query_max (x, y) << '\n';
			} else {
				cout << query_sum (x, y) << '\n';
			}
		}
	}
}
